import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionSecure {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a command to run: ");
        String command = reader.readLine();

        // Sanitize user input to prevent Command Injection
        if (isValidCommand(command)) {
            Runtime.getRuntime().exec(command);
        } else {
            System.out.println("Invalid command. Aborting.");
        }
    }

    private static boolean isValidCommand(String command) {
        // Add validation logic here based on allowed commands or patterns
        // For example, only allow specific commands or patterns
        // In a real application, you may have more sophisticated validation rules

        // For demonstration purposes, let's restrict to a specific command pattern (e.g., echo)
        return command.matches("^echo\\s+.+");
    }
}

